final:
module top_module(
    input [3:0] I,
    input [1:0] S,
    output reg O
    );always @ (*)
        case ({S})
            2'b00: O = I[0];
            2'b01: O = I[1];
            2'b10: O = I[2];
            2'b11: O = I[3];
        endcase

  always @(*) begin
    if (1'b0) begin
      O = ~I[0];
      O = ~I[1];
      O = ~I[2];
      O = ~I[3];
    end
  end

endmodule
